#!/usr/bin/env bash
# achilles-rupture.sh — 跟腱断裂 (Achilles Rupture) 评估 + 治疗决策 SOP walkthrough for 足踝外科.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="足踝外科"
WORKFLOW="跟腱断裂 (Achilles Rupture) 评估 + 治疗决策"

usage() {
  cat <<EOF
achilles-rupture.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./achilles-rupture.sh             # interactive
  ./achilles-rupture.sh --dry-run
  ./achilles-rupture.sh --json
  ./achilles-rupture.sh --explain
  ./achilles-rupture.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "跟腱断裂 (Achilles Rupture) 评估 + 治疗决策" 工作流。

一句话: 从急性跟腱断裂诊断到手术 vs 保守 vs 微创 决策的标准流程

入门 SOP 共 6 步, 失败模式自检 11 项。

相关心智模型:
  • 保守治疗优先于手术 (3-6 月黄金期): 90% 的足踝慢性病变不需要手术, 但很多医生 / 患者直接跳到手术决策, 跳过保守治疗黄金期.
  • 影像学发现 ≠ 临床症状原因 (跟着症状走): MRI 看到的「异常」很多跟患者主诉无关. 影像跟症状对不上时, 跟着症状走, 不是跟着影像走.

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**病史**: 受伤机制 (突然蹬地 / 急停急起) + 「pop 声」 + 不能踮脚 + 既往跟腱病史 + 既往氟喹诺酮 / 类固醇使用 (跟腱风险因素)"
  "**体格** (Thompson 试验是 gold standard):"
  "**影像确认**:"
  "**决策 — 手术 vs 保守**:"
  "**术后 / 保守康复**:"
  "**复发预防**: 永久 awareness — 跟腱断裂后再断率 5-10%, 对侧断率 5-10%"
)
declare -a FAILURE_MODES=(
  "**默认手术 / 默认保守** — 不个体化决策"
  "**6 周石膏不负重** — 现代 functional 早期负重时代落后做法"
  "**过早回运动** (普通人 < 6 月 / 运动员 < 9 月) → 再断率高"
  "**慢性断裂当急性处理** → 单纯端端缝合不够, 需增强"
  "**跟腱挛缩没矫** (Silverskiöld 阳性) → 复发风险"
  "**氟喹诺酮 / 慢性类固醇用药史漏问** → 风险评估不足"
  "**关键决策点**:"
  "急性 ≤ 4 周 + 普通人 / 老年 / 高风险 → 保守 (functional bracing)"
  "急性 ≤ 4 周 + 中年健康 / 运动需求 → 微创 mini-open"
  "急性 ≤ 4 周 + 复杂 / 高需求 → 开放 + 必要增强"
  "慢性 > 4 周 → 多需手术 + 增强术式"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "achilles-rupture-walkthrough"
fi
